import React, { useEffect, useState } from 'react'
import Header from './Header';
import { test_img } from '../assets/img';

export const Game = () => {
    const [imgWidth, setImgWidth] = useState(0)
    const [imgHeight, setImgHeight] = useState(0)

    const [currentText, setCurrentText] = useState("")
    const [currentWord, setCurrentWord] = useState("")

    useEffect(() => {
        const typingWord = setInterval(() => {
            if(currentText.length < currentWord.length) {
                currentText = currentWord.slice(0, currentText.length + 1);
            }
        }, speed)

    }, [speed, currentText, currentWord])

  return (
    <div className='flex flex-col h-screen'>
        <Header/>
        <div className='flex flex-1 w-full justify-center overflow-hidden'>
            <img src={test_img} className=' h-full object-contain'
            onLoad={
                (e) => {
                    setImgWidth(e.currentTarget.width)
                    setImgHeight(e.currentTarget.height)
                }
            }
            />
        </div>

        <TextBox width={imgWidth} height={imgHeight}></TextBox>

    </div>
  )
}

const TextBox = ({height, width, name, text}) => (
    <div className="fixed h-16 bg-[rgba(128,128,255,0.5)] blur-md  bottom-0 left-1/2 -translate-x-1/2"
    style={{
        width: `${width}px`,
        height: `${height/3}px`
    }}
    ></div>
)

export default Game;
